const CAPITAL_MARKS = [1000, 5000, 10000, 25000, 50000, 100000, 250000, 500000, 1000000];
const CONTRIBUTION_MARKS = [0, 100, 250, 500, 1000, 2500, 5000, 10000];

function formatCurrency(val) {
  if (val >= 1000000) return '$' + (val / 1000000).toFixed(val % 1000000 === 0 ? 0 : 1) + 'M';
  if (val >= 1000) return '$' + (val / 1000).toFixed(val % 1000 === 0 ? 0 : 1) + 'K';
  return '$' + val;
}

function SnapSlider({ marks, value, onChange, label, formatFn }) {
  const idx = marks.indexOf(value);
  const sliderIdx = idx >= 0 ? idx : 0;

  return (
    <div className={s.sliderWrap}>
      <div className={s.sliderHeader}>
        <span className={s.sliderLabel}>{label}</span>
        <span className={s.sliderValue}>{formatFn(value)}</span>
      </div>
      <input
        type="range"
        min={0}
        max={marks.length - 1}
        value={sliderIdx}
        onChange={e => onChange(marks[parseInt(e.target.value)])}
        className={s.slider}
      />
      <div className={s.sliderMarks}>
        <span>{formatFn(marks[0])}</span>
        <span>{formatFn(marks[Math.floor(marks.length / 2)])}</span>
        <span>{formatFn(marks[marks.length - 1])}</span>
      </div>
    </div>
  );
}

