function StepActivate({ path, onBack, api, simResult, goal, riskTolerance, capital, contribution, horizon }) {
  const nav = useNavigate();
  const [completing, setCompleting] = useState(false);
  const [error, setError] = useState('');

  const strategyKeys = useMemo(() => {
    // Map strategy names from sim result to strategy pool keys
    if (simResult?.strategy_mix) {
      return simResult.strategy_mix.map(name => {
        const found = STRATEGY_POOL.find(s =>
          s.label.toLowerCase() === name.toLowerCase() ||
          s.key.toLowerCase() === name.toLowerCase().replace(/\s+/g, '_')
        );
        return found ? found.key : name.toLowerCase().replace(/\s+/g, '_');
      });
    }
    return ['breakout', 'bullish_pullback', 'trend_play', 'nice_chart', 'golden_cross'];
  }, [simResult]);

  const handleActivate = async () => {
    setCompleting(true);
    setError('');

    try {
      // Save profile preferences
      await api.savePreferences({
        trading_path: path,
        investment_goal: goal,
        risk_tolerance: riskTolerance || simResult?.parameters?.risk_tolerance || 'moderate',
      });

      // Save recommended strategies via AI selector
      const aiSelRes = await api.aiSelectStrategies({
        goal,
        risk_tolerance: riskTolerance || 'moderate',
        capital,
        trading_path: path,
        selected_strategies: strategyKeys,
      });

      // Also save via legacy endpoint
      await api.saveStrategies(strategyKeys);

      // Complete the wizard session
      await api.wizardComplete({
        trading_path: path,
        goal,
        risk_tolerance: riskTolerance || 'moderate',
        initial_capital: capital,
        monthly_contribution: contribution,
        time_horizon_years: horizon,
        selected_strategies: strategyKeys,
      });

      // Mark onboarding complete
      const res = await api.complete();
      if (res.ok) {
        try {
          const stored = JSON.parse(localStorage.getItem('aura_user') || '{}');
          stored.onboarding_completed = true;
          stored.trading_path = path;
          stored.investment_goal = goal;
          localStorage.setItem('aura_user', JSON.stringify(stored));
        } catch (e) { /* ignore */ }

        nav('/', { replace: true });
      } else {
        setError(res.error || 'Failed to complete setup');
        setCompleting(false);
      }
    } catch (e) {
      setError('Something went wrong. Please try again.');
      setCompleting(false);
    }
  };

  if (path === 'paper') return <StepConnectionPaper onNext={handleActivate} onBack={onBack} />;
  if (path === 'live') return <StepConnectionLive onNext={handleActivate} onBack={onBack} api={api} />;
  return <StepConnectionObserver onNext={handleActivate} onBack={onBack} />;
}


