function StepAlias({ onNext, onBack, alias, setAlias, aliasError, setAliasError, api }) {
  const [saving, setSaving] = useState(false);

  const handleContinue = async () => {
    const trimmed = alias.trim();
    if (trimmed.length < 3 || trimmed.length > 20) {
      setAliasError('Alias must be 3-20 characters');
      return;
    }
    if (!(/^[a-zA-Z0-9_ -]+$/.test(trimmed))) {
      setAliasError('Letters, numbers, spaces, hyphens, and underscores only');
      return;
    }
    setAliasError('');
    setSaving(true);
    const res = await api.setAlias(trimmed);
    setSaving(false);
    if (res.ok) {
      onNext();
    } else {
      setAliasError(res.error || 'Failed to save alias');
    }
  };

  return (
    <div className={s.profileWrap} style={{ maxWidth: 560 }}>
      <h2 className={s.stepHeading}>Create Your Public Alias</h2>
      <p className={s.stepSub}>
        This is how you'll appear on leaderboards and tournaments. No real names required.
      </p>

      <div className={s.fieldWrap}>
        <input
          type="text"
          className={s.textInput}
          placeholder="e.g. AlphaHunter, QuantSniper..."
          value={alias}
          onChange={e => { setAlias(e.target.value); setAliasError(''); }}
          maxLength={20}
        />
        <p style={{ fontSize: 12, color: T.textSecondary, marginTop: 8 }}>
          3-20 characters. Letters, numbers, spaces, hyphens.
        </p>
        {aliasError && <p style={{ color: T.red, fontSize: 13, marginTop: 4 }}>{aliasError}</p>}
      </div>

      <NavButtons onBack={onBack} onNext={handleContinue} nextDisabled={alias.trim().length < 3} loading={saving} />
    </div>
  );
}


