// STEP 6: Create Your Agent
// ══════════════════════════════════════════════════════════════════════════

function StepAgent({ onNext, onBack, agentName, setAgentName, agentMarket, setAgentMarket, tradingPath, api }) {
  const [saving, setSaving] = useState(false);
  const [agentError, setAgentError] = useState('');

  const handleContinue = async () => {
    const trimmed = agentName.trim();
    if (trimmed.length < 1 || trimmed.length > 30) {
      setAgentError('Agent name must be 1-30 characters');
      return;
    }
    setAgentError('');
    setSaving(true);
    const res = await api.createAgent({
      name: trimmed,
      market: agentMarket,
      mode: tradingPath === 'paper' ? 'paper' : 'live',
    });
    setSaving(false);
    if (res.ok) {
      onNext();
    } else {
      setAgentError(res.error || 'Failed to create agent');
    }
  };

  return (
    <div className={s.profileWrap} style={{ maxWidth: 560 }}>
      <h2 className={s.stepHeading}>Create Your First Agent</h2>
      <p className={s.stepSub}>
        Agents execute your trading strategies. Name your first one — you can add more later.
      </p>

      <div className={s.fieldWrap}>
        <input
          type="text"
          className={s.textInput}
          placeholder="e.g. My Alpha Bot, Strategy Runner..."
          value={agentName}
          onChange={e => { setAgentName(e.target.value); setAgentError(''); }}
          maxLength={30}
        />
      </div>

      <div style={{ display: 'flex', gap: 12, marginBottom: 16 }}>
        {['equity', 'crypto'].map(m => (
          <button
            key={m}
            onClick={() => setAgentMarket(m)}
            style={{
              flex: 1, padding: '14px', borderRadius: 8,
              border: `1px solid ${agentMarket === m ? T.blue : T.border}`,
              background: agentMarket === m ? T.blue + '11' : 'transparent',
              color: agentMarket === m ? T.blue : T.textSecondary,
              cursor: 'pointer', fontSize: 14, fontWeight: 600,
              fontFamily: 'inherit',
            }}
          >
            {m === 'equity' ? 'Equity / Stocks' : 'Crypto'}
          </button>
        ))}
      </div>

      {agentError && <div className={s.errorBanner}>{agentError}</div>}

      <NavButtons onBack={onBack} onNext={handleContinue} nextDisabled={agentName.trim().length < 1} loading={saving} />
    </div>
  );
}


// ══════════════════════════════════════════════════════════════════════════
// STEP 7: Risk Confirmation
// ══════════════════════════════════════════════════════════════════════════

function StepRiskConfirmation({ onNext, onBack, riskChecks, setRiskChecks, tradingPath, api }) {
  const [saving, setSaving] = useState(false);
  const [riskError, setRiskError] = useState('');

  const allChecked = riskChecks.risk && riskChecks.killSwitch && riskChecks.paper;

  const handleContinue = async () => {
    if (!allChecked) return;
    setRiskError('');
    setSaving(true);
    const res = await api.confirmRisk({
      confirmed_risk_understanding: riskChecks.risk,
      confirmed_kill_switch_aware: riskChecks.killSwitch,
      confirmed_paper_first: riskChecks.paper,
      confirmed_live_mode: tradingPath === 'live',
    });
    setSaving(false);
    if (res.ok) {
      onNext();
    } else {
      setRiskError(res.error || 'Failed to save risk confirmation');
    }
  };

  const RISK_ITEMS = [
    { key: 'risk', label: 'I understand that all trading involves risk and past performance does not guarantee future results.' },
    { key: 'killSwitch', label: 'I know how to use the Kill Switch to immediately halt all trading activity.' },
    { key: 'paper', label: tradingPath === 'paper'
        ? 'I am starting in Paper Trading mode with simulated funds.'
        : 'I am connecting a live brokerage account and trading with real capital.' },
  ];

  return (
    <div className={s.profileWrap} style={{ maxWidth: 600 }}>
      <h2 className={s.stepHeading}>Risk Acknowledgment</h2>
      <p className={s.stepSub}>
        Before activating, please confirm you understand the following:
      </p>

      <div style={{ display: 'flex', flexDirection: 'column', gap: 12, marginTop: 16 }}>
        {RISK_ITEMS.map(item => (
          <label key={item.key} style={{
            display: 'flex', alignItems: 'flex-start', gap: 10, cursor: 'pointer',
            padding: '12px', background: T.surface, borderRadius: 8,
            border: `1px solid ${riskChecks[item.key] ? T.green + '40' : T.border}`,
            transition: 'border-color 0.2s ease',
          }}>
            <input
              type="checkbox"
              checked={riskChecks[item.key] || false}
              onChange={() => setRiskChecks(prev => ({ ...prev, [item.key]: !prev[item.key] }))}
              style={{ marginTop: 3, accentColor: T.green }}
            />
            <span style={{ fontSize: 14, color: T.textPrimary, lineHeight: 1.5 }}>{item.label}</span>
          </label>
        ))}
      </div>

      {riskError && <div className={s.errorBanner} style={{ marginTop: 12 }}>{riskError}</div>}

      <NavButtons onBack={onBack} onNext={handleContinue} nextDisabled={!allChecked} loading={saving} />
    </div>
  );
}


// ══════════════════════════════════════════════════════════════════════════
// Main Wizard Container
// ══════════════════════════════════════════════════════════════════════════

export default function OnboardingPage() {
  usePageTitle('Get Started');
  const nav = useNavigate();
  const [step, setStep] = useState(0);
  const [selectedPath, setSelectedPath] = useState(null);
  const [alias, setAlias] = useState('');
  const [aliasError, setAliasError] = useState('');
  const [goal, setGoal] = useState(null);
  const [riskTolerance, setRiskTolerance] = useState('moderate');
  const [capital, setCapital] = useState(10000);
  const [contribution, setContribution] = useState(500);
  const [horizon, setHorizon] = useState(3);
  const [simResult, setSimResult] = useState(null);
  const [simLoading, setSimLoading] = useState(false);
  const [simError, setSimError] = useState('');
  const [agentName, setAgentName] = useState('');
  const [wizardSessionId, setWizardSessionId] = useState(null);
  const [agentMarket, setAgentMarket] = useState('equity');
  const [riskChecks, setRiskChecks] = useState({ risk: false, killSwitch: false, paper: false });

  const api = useOnboarding();

  // Check if user already completed onboarding & restore wizard progress
  useEffect(() => {
    const loadStatus = async () => {
      const res = await api.checkStatus();
      if (res.ok && res.data?.onboarding_completed) {
        nav('/', { replace: true });
        return;
      }
      // Try restoring wizard progress from the backend
      const progressRes = await api.wizardProgress();
      if (progressRes.ok && progressRes.data) {
        const pg = progressRes.data;
        if (pg.session_id) setWizardSessionId(pg.session_id);
        if (pg.current_step > 0 && pg.current_step < 8) setStep(pg.current_step);
        if (pg.trading_path) setSelectedPath(pg.trading_path);
        if (pg.goal) setGoal(pg.goal);
        if (pg.risk_tolerance) setRiskTolerance(pg.risk_tolerance);
        if (pg.alias) setAlias(pg.alias);
        if (typeof pg.capital === 'number') setCapital(pg.capital);
        if (typeof pg.contribution === 'number') setContribution(pg.contribution);
        if (typeof pg.horizon === 'number') setHorizon(pg.horizon);
      }
    };
    loadStatus();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Start wizard session when entering step 1 (after path selection)
  const startWizardSession = useCallback(async () => {
    const params = {
      trading_path: selectedPath,
      goal,
      risk_tolerance: riskTolerance,
      initial_capital: capital,
      monthly_contribution: contribution,
      time_horizon_years: horizon,
    };
    const res = await api.wizardStart(params);
    if (res.ok && res.data?.session_id) {
      setWizardSessionId(res.data.session_id);
    }
  }, [api, selectedPath, goal, riskTolerance, capital, contribution, horizon]);

  // Run Monte Carlo simulation when entering step 4 (projection)
  // Also fetches AI strategy recommendations from the backend
  const runSimulation = useCallback(async () => {
    if (!goal) return;
    setSimLoading(true);
    setSimError('');
    setSimResult(null);

    // Start or update wizard session with latest parameters
    const wizParams = {
      trading_path: selectedPath,
      goal,
      risk_tolerance: riskTolerance,
      initial_capital: capital,
      monthly_contribution: contribution,
      time_horizon_years: horizon,
    };
    const wizRes = await api.wizardStart(wizParams);
    if (wizRes.ok && wizRes.data?.session_id) {
      setWizardSessionId(wizRes.data.session_id);
    }

    // Get AI-matched strategy recommendations
    const aiRes = await api.aiSelectStrategies({
      goal,
      risk_tolerance: riskTolerance,
      capital,
      trading_path: selectedPath,
    });

    // Run simulation with backend
    const res = await api.simulate({
      goal,
      initial_capital: capital,
      monthly_contribution: contribution,
      time_horizon_years: horizon,
      risk_tolerance: riskTolerance,
    });

    setSimLoading(false);
    if (res.ok) {
      // Merge AI suggestions into sim result if available
      const simData = { ...res.data };
      if (aiRes.ok && aiRes.data) {
        if (aiRes.data.recommended_strategies) {
          simData.strategy_mix = aiRes.data.recommended_strategies.map(
            s => s.label || s.name || s.key
          );
        }
        if (aiRes.data.allocation) {
          simData.allocation = { ...simData.allocation, ...aiRes.data.allocation };
        }
      }
      setSimResult(simData);
    } else {
      // Fallback: try getting recommendations from wizard endpoint
      const recRes = await api.wizardRecommendations();
      if (recRes.ok && recRes.data) {
        setSimResult(recRes.data);
      } else {
        setSimError(res.error || 'Simulation failed. Please try again.');
      }
    }
  }, [api, goal, capital, contribution, horizon, riskTolerance, selectedPath]);

  const next = useCallback(() => {
    setStep(s => {
      const nextStep = Math.min(s + 1, 7);
      // Start wizard session when leaving the welcome step
      if (s === 0 && selectedPath) {
        setTimeout(startWizardSession, 50);
      }
      // Trigger simulation when moving to step 4 (projection)
      if (nextStep === 4) {
        setTimeout(runSimulation, 50);
      }
      return nextStep;
    });
  }, [runSimulation, startWizardSession, selectedPath]);

  const back = useCallback(() => setStep(s => Math.max(s - 1, 0)), []);

  const handleSkipOnboarding = async () => {
    try { await api.wizardComplete({ skipped: true }); } catch (e) { /* ignore */ }
    try { await api.complete(); } catch (e) { /* ignore */ }
    try {
      const stored = JSON.parse(localStorage.getItem('aura_user') || '{}');
      stored.onboarding_completed = true;
      localStorage.setItem('aura_user', JSON.stringify(stored));
    } catch (e) { /* ignore */ }
    localStorage.setItem('aura_onboarding_skipped', 'true');
    nav('/', { replace: true });
  };

  return (
    <div className={s.page}>
      <div className={s.container}>
        {step > 0 && <StepIndicator current={step} />}

        <div key={step} className={s.stepContent} style={{ marginTop: step === 0 ? 40 : 24 }}>
          {step === 0 && (
            <StepWelcome
              onNext={next}
              selectedPath={selectedPath}
              setSelectedPath={setSelectedPath}
              onSkip={handleSkipOnboarding}
            />
          )}
          {step === 1 && (
            <StepAlias
              onNext={next}
              onBack={back}
              alias={alias}
              setAlias={setAlias}
              aliasError={aliasError}
              setAliasError={setAliasError}
              api={api}
            />
          )}
          {step === 2 && (
            <StepGoal
              onNext={next}
              onBack={back}
              goal={goal}
              setGoal={setGoal}
              riskTolerance={riskTolerance}
              setRiskTolerance={setRiskTolerance}
            />
          )}
          {step === 3 && (
            <StepCapital
              onNext={next}
              onBack={back}
              capital={capital}
              setCapital={setCapital}
              contribution={contribution}
              setContribution={setContribution}
              horizon={horizon}
              setHorizon={setHorizon}
            />
          )}
          {step === 4 && (
            <StepProjection
              onNext={next}
              onBack={back}
              simResult={simResult}
              simLoading={simLoading}
              simError={simError}
              api={api}
            />
          )}
          {step === 5 && (
            <StepAgent
              onNext={next}
              onBack={back}
              agentName={agentName}
              setAgentName={setAgentName}
              agentMarket={agentMarket}
              setAgentMarket={setAgentMarket}
              tradingPath={selectedPath}
              api={api}
            />
          )}
          {step === 6 && (
            <StepRiskConfirmation
              onNext={next}
              onBack={back}
              riskChecks={riskChecks}
              setRiskChecks={setRiskChecks}
              tradingPath={selectedPath}
              api={api}
            />
          )}
          {step === 7 && (
            <StepActivate
              path={selectedPath}
              onBack={back}
              api={api}
              simResult={simResult}
              goal={goal}
              riskTolerance={riskTolerance}
              capital={capital}
              contribution={contribution}
              horizon={horizon}
            />
          )}
        </div>
      </div>
    </div>
  );
}
