/**
 * AURA TRADING DESK — Onboarding Wizard API Hook
 * Wraps all onboarding endpoints with auth headers, including wizard session,
 * AI strategy selector, alias, agents, and risk-confirmation.
 */
import { useState, useCallback } from 'react';
import { getApiBase } from '../utils/platform';

const apiBase = getApiBase() + '/onboarding';

function authHeaders() {
  const token = localStorage.getItem('aura_token');
  return {
    'Content-Type': 'application/json',
    ...(token ? { Authorization: `Bearer ${token}` } : {}),
  };
}

export default function useOnboarding() {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const request = useCallback(async (method, path, body = null, absoluteUrl = null) => {
    setLoading(true);
    setError('');
    try {
      const opts = { method, headers: authHeaders() };
      if (body) opts.body = JSON.stringify(body);
      const url = absoluteUrl || (apiBase + path);
      const res = await fetch(url, opts);
      const data = await res.json();
      if (!res.ok) {
        const msg = data.detail || 'Request failed';
        setError(msg);
        setLoading(false);
        return { ok: false, error: msg };
      }
      setLoading(false);
      return { ok: true, data };
    } catch (e) {
      const msg = 'Connection failed. Is the API running?';
      setError(msg);
      setLoading(false);
      return { ok: false, error: msg };
    }
  }, []);

  const checkStatus = useCallback(() => request('GET', '/status'), [request]);

  const saveIBKR = useCallback((access_token, access_token_secret) =>
    request('POST', '/ibkr-credentials', { access_token, access_token_secret }), [request]);

  const testIBKR = useCallback(() =>
    request('POST', '/ibkr-credentials/test'), [request]);

  const saveRisk = useCallback((settings) =>
    request('POST', '/risk-settings', settings), [request]);

  const saveStrategies = useCallback((strategy_keys) =>
    request('POST', '/strategies', { strategy_keys }), [request]);

  const savePreferences = useCallback((prefs) =>
    request('POST', '/trading-preferences', prefs), [request]);

  const complete = useCallback(() =>
    request('POST', '/complete'), [request]);

  // ── Multi-broker credential helpers ──────────────────────
  const saveBrokerCredentials = useCallback((brokerId, credentials, isPaper = false) =>
    request('POST', '', { credentials, is_paper: isPaper }, `${getApiBase()}/brokers/${brokerId}/credentials`), [request]);

  const testBroker = useCallback((brokerId, credentials, isPaper = false) =>
    request('POST', '', { credentials, is_paper: isPaper }, `${getApiBase()}/brokers/${brokerId}/test`), [request]);

  // ── Goal-based Monte Carlo simulation ──────────────────
  const simulate = useCallback((params) =>
    request('POST', '/simulate', params), [request]);

  // ── Alias, Agent, Risk Confirmation ──────────────────
  const setAlias = useCallback((display_name) =>
    request('POST', '/alias', { display_name }), [request]);

  const createAgent = useCallback((agentData) =>
    request('POST', '/agents', agentData), [request]);

  const listAgents = useCallback(() =>
    request('GET', '/agents'), [request]);

  const confirmRisk = useCallback((confirmations) =>
    request('POST', '/risk-confirmation', confirmations), [request]);

  // ── Wizard session endpoints (/api/wizard/*) ───────────────
  const wizardStart = useCallback((params) =>
    request('POST', '', params, `${getApiBase()}/wizard/start`), [request]);

  const wizardProgress = useCallback(() =>
    request('GET', '', null, `${getApiBase()}/wizard/progress`), [request]);

  const wizardRecommendations = useCallback(() =>
    request('GET', '', null, `${getApiBase()}/wizard/recommendations`), [request]);

  const wizardComplete = useCallback((params) =>
    request('POST', '', params, `${getApiBase()}/wizard/complete`), [request]);

  // ── AI strategy selector endpoints (/api/ai/strategy-selector/*) ──
  const aiSelectStrategies = useCallback((params) =>
    request('POST', '', params, `${getApiBase()}/ai/strategy-selector/select-strategies`), [request]);

  const aiStrategySuggestions = useCallback(() =>
    request('GET', '', null, `${getApiBase()}/ai/strategy-selector/strategy-suggestions`), [request]);

  // ── Strategy catalogue (/api/strategies) ───────────────────
  const fetchStrategyCatalogue = useCallback(() =>
    request('GET', '', null, `${getApiBase()}/strategies`), [request]);

  return {
    loading, error, setError,
    checkStatus, saveIBKR, testIBKR,
    saveRisk, saveStrategies, savePreferences,
    complete, saveBrokerCredentials, testBroker,
    simulate, setAlias, createAgent, listAgents, confirmRisk,
    wizardStart, wizardProgress, wizardRecommendations, wizardComplete,
    aiSelectStrategies, aiStrategySuggestions, fetchStrategyCatalogue,
  };
}
